import os
desktop = os.path.join(os.path.expanduser('~'), 'Desktop')
html_content = '''<!DOCTYPE html>
<html dir="rtl" lang="ar">
<head>
<meta charset="UTF-8">
<link href="https://fonts.googleapis.com/css2?family=Amiri:wght@400;700&family=Tajawal:wght@500;700;900&display=swap" rel="stylesheet">
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { width: 1920px; height: 1080px; background: radial-gradient(ellipse at center, #5c1a1a 0%, #2a0a0a 50%, #0a0000 100%); display: flex; flex-direction: column; justify-content: center; align-items: center; font-family: 'Amiri', 'Tajawal', serif; overflow: hidden; position: relative; }
.border-frame { position: absolute; top: 20px; left: 20px; right: 20px; bottom: 20px; border: 3px solid #b8860b; outline: 1px solid #daa52080; outline-offset: 8px; }
.corner { position: absolute; width: 40px; height: 40px; }
.corner::before, .corner::after { content: '\u25C6'; color: #ffd700; font-size: 24px; position: absolute; }
.corner-tl { top: 8px; left: 8px; }
.corner-tr { top: 8px; right: 8px; }
.corner-bl { bottom: 8px; left: 8px; }
.corner-br { bottom: 8px; right: 8px; }
.stars { position: absolute; width: 100%; height: 100%; background-image: radial-gradient(2px 2px at 10% 15%, #ffd70060, transparent), radial-gradient(2px 2px at 85% 20%, #ffd70040, transparent), radial-gradient(3px 3px at 15% 80%, #ffd70050, transparent), radial-gradient(2px 2px at 90% 75%, #ffd70030, transparent), radial-gradient(2px 2px at 50% 10%, #ffd70040, transparent), radial-gradient(2px 2px at 30% 90%, #ffd70035, transparent), radial-gradient(2px 2px at 70% 85%, #ffd70045, transparent); }
.diamonds { position: absolute; width: 100%; height: 100%; opacity: 0.15; }
.diamond { position: absolute; width: 20px; height: 20px; background: #daa520; transform: rotate(45deg); }
.main-text { font-family: 'Amiri', serif; font-size: 72px; font-weight: 700; color: #ffd700; text-shadow: 0 0 30px #ffd70040, 0 4px 8px #00000080, 0 0 60px #b8860b30; z-index: 10; text-align: center; line-height: 1.4; }
.separator { width: 500px; height: 3px; margin: 20px auto; background: linear-gradient(90deg, transparent, #ffd700, transparent); z-index: 10; position: relative; }
.separator::before { content: '\u25C6'; position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); color: #ffd700; font-size: 16px; }
.sub-text { font-family: 'Tajawal', sans-serif; font-size: 36px; font-weight: 500; color: #ffe4b5; text-shadow: 0 2px 4px #00000060; z-index: 10; margin-top: 10px; letter-spacing: 2px; }
</style>
</head>
<body>
<div class="border-frame"></div>
<div class="corner corner-tl"></div>
<div class="corner corner-tr"></div>
<div class="corner corner-bl"></div>
<div class="corner corner-br"></div>
<div class="stars"></div>
<div class="diamonds">
<div class="diamond" style="top:8%;left:5%"></div>
<div class="diamond" style="top:12%;left:88%"></div>
<div class="diamond" style="top:75%;left:8%"></div>
<div class="diamond" style="top:80%;left:90%"></div>
<div class="diamond" style="top:5%;left:45%"></div>
<div class="diamond" style="top:88%;left:50%"></div>
</div>
<div class="main-text">\u0645\u0631\u062d\u0628\u0627\u064b \u0628\u0643\u0645 \u0641\u064a \u0645\u0637\u0639\u0645 \u0627\u0644\u0631\u0643\u0646 \u0627\u0644\u062c\u0645\u064a\u0644 \u0639\u0646\u062f \u0627\u0628\u0631\u0627\u0647\u064a\u0645</div>
<div class="separator"></div>
<div class="sub-text">\u2728 \u0623\u0637\u0628\u0627\u0642 \u0634\u0647\u064a\u0629 \u0648\u0623\u062c\u0648\u0627\u0621 \u0631\u0627\u0642\u064a\u0629 \u2728</div>
</body>
</html>'''
file_path = os.path.join(desktop, 'restaurant_design.html')
with open(file_path, 'w', encoding='utf-8') as f:
    f.write(html_content)
print(f'HTML file created at: {file_path}')
print(f'File size: {os.path.getsize(file_path)} bytes')
